55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const DEDUCTIBLE = 100;
59	const CAP_MULTIPLIER = 2;
60	const CURSED_SURCHARGE_RATE = 0.5;
61	const HIGH_ENCHANTMENT_RATE = 0.3;
62	const HIGH_ENCHANTMENT_THRESHOLD = 5;
63	const FIRST_INSURANCE_RATE = 0.1;
64	const LOYALTY_DISCOUNT_RATE = 0.2;
65	const LOYALTY_YEARS_THRESHOLD = 2;
66	const FOLLOWUP_DISCOUNT_RATE = 0.15;
67	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
68	  sword: 100,
69	  amulet: 60,
70	  staff: 80,
71	  potion: 40,
72	  rune: 25,
73	  moonstone: 25,
74	};
75	
76	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
77	  sword: 1000,
78	  amulet: 600,
79	  staff: 800,
80	  potion: 400,
81	  rune: 250,
82	  moonstone: 250,
83	};
84	
85	const insuranceValue = (item: Item): number =>
86	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
87	
88	const insuranceSum = (items: Item[]): number =>
89	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
90	
91	const basePremium = (item: Item): number =>
92	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
93	
94	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
95	
96	const groupByType = (items: Item[]): Map<string, Item[]> => {
97	  const groups = new Map<string, Item[]>();
98	  for (const item of items) {
99	    const existing = groups.get(item.type) ?? [];
100	    existing.push(item);
101	    groups.set(item.type, existing);
102	  }
103	  return groups;
104	};
105	
106	const sumBasePremiums = (items: Item[]): number =>
107	  items.reduce((sum, item) => sum + basePremium(item), 0);
108	
109	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
110	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
111	
112	const groupTotal = (type: string, group: Item[]): number =>
113	  isCompleteComponentBlock(type, group)
114	    ? COMPONENT_BLOCK_PRICE
115	    : sumBasePremiums(group);
116	
117	const policyBase = (items: Item[]): number =>
118	  Array.from(groupByType(items)).reduce(
119	    (sum, [type, group]) => sum + groupTotal(type, group),
120	    0,
121	  );
122	
123	const perItemSurcharge = (
124	  items: Item[],
125	  predicate: (item: Item) => boolean,
126	  rate: number,
127	): number =>
128	  items.reduce(
129	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
130	    0,
131	  );
132	
133	const isCursed = (item: Item): boolean => item.cursed === true;
134	
135	const isHighlyEnchanted = (item: Item): boolean =>
136	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
137	
138	const firstInsuranceSurcharge = (base: number): number =>
139	  base * FIRST_INSURANCE_RATE;
140	
141	const loyaltyDiscount = (base: number, customer: Customer): number =>
142	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
143	    ? base * LOYALTY_DISCOUNT_RATE
144	    : 0;
145	
146	const followupDiscount = (base: number, quoteIndex: number): number =>
147	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
148	
149	const quotePremium = (
150	  items: Item[],
151	  customer: Customer,
152	  quoteIndex: number,
153	): number => {
154	  const base = policyBase(items);
155	  const modifiedBase =
156	    base +
157	    perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
158	    perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
159	    firstInsuranceSurcharge(base) -
160	    loyaltyDiscount(base, customer) -
161	    followupDiscount(base, quoteIndex);
162	  return Math.ceil(modifiedBase) + PROCESSING_FEE;
163	};
