189	  const payout = step.incident.damages.reduce(
190	    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
191	    0,
192	  );
193	  policy.remainingCap -= payout;
194	  return { payout, remainingCap: policy.remainingCap };
195	};
196	
197	const processStep = (step: Step, state: ScenarioState): StepResult =>
198	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
