interface ScenarioState {
  customer: Customer;
  policies: Map<number, Policy>;
  quoteIndex: number;
  stepIndex: number;
}

const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
  state.policies.set(state.stepIndex, {
    items: step.items,
    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
  });
  return {
    premium: quotePremium(step.items, state.customer, state.quoteIndex),
  };
};

const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
  const policy = state.policies.get(step.policy) as Policy;
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
    0,
  );
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

const processStep = (step: Step, state: ScenarioState): StepResult =>
  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);

const quoteIndexAt = (steps: Step[], stepIndex: number): number =>
  steps.slice(0, stepIndex).filter((s) => s.op === "quote").length;

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const policies = new Map<number, Policy>();
  const results: StepResult[] = scenario.steps.map((step, stepIndex) =>
    processStep(step, {
      customer: scenario.customer,
      policies,
      quoteIndex: quoteIndexAt(scenario.steps, stepIndex),
      stepIndex,
    }),
  );
  return { results };
};
